            writeSecret,
            token,
            syncEnabled,
            dhtEnabled,
            pexEnabled,
        )
        let response = try await client.invoke(request)
        switch response {
        case .repository(let value): return Repository(client, value)
        default:
            throw UnexpectedResponse()
        }
    }

