public class Repository {
    internal let client: Client
    public let handle: RepositoryHandle

    internal init(_ client: Client, _ handle: RepositoryHandle) {
        self.client = client
        self.handle = handle
    }

    /// Closes the repository.
    public func close() async throws {
        let request = Request.repositoryClose(
            handle,
        )
        let response = try await client.invoke(request)
        switch response {
        case .unit:
            return
        default:
            throw UnexpectedResponse()
        }
    }

    /// Creates a new directory at the given path in the repository.
    public func createDirectory(_ path: String) async throws {
        let request = Request.repositoryCreateDirectory(
            handle,
            path,
        )
        let response = try await client.invoke(request)
        switch response {
        case .unit:
            return
        default:
            throw UnexpectedResponse()
        }
    }

    /// Creates a new file at the given path in the repository.
    public func createFile(_ path: String) async throws -> File {
        let request = Request.repositoryCreateFile(
            handle,
            path,
        )
        let response = try await client.invoke(request)
        switch response {
        case .file(let value): return File(client, value)
        default:
            throw UnexpectedResponse()
        }
    }

    /// Creates mirror of this repository on the given cache server host.
    ///
    /// Cache servers relay traffic between Ouisync peers and also temporarily store data. They are
    /// useful when direct P2P connection fails (e.g. due to restrictive NAT) and also to allow
    /// syncing when the peers are not online at the same time (they still need to be online within
    /// ~24 hours of each other).
    ///
    /// Requires the repository to be opened in write mode.
    public func createMirror(_ host: String) async throws {
        let request = Request.repositoryCreateMirror(
            handle,
            host,
        )
        let response = try await client.invoke(request)
        switch response {
        case .unit:
            return
        default:
            throw UnexpectedResponse()
        }
    }

    /// Delete the repository
    public func delete() async throws {
        let request = Request.repositoryDelete(
            handle,
        )
        let response = try await client.invoke(request)
        switch response {
        case .unit:
            return
        default:
            throw UnexpectedResponse()
        }
    }

    /// Deletes mirror of this repository from the given cache server host.
    ///
    /// Requires the repository to be opened in write mode.
    public func deleteMirror(_ host: String) async throws {
        let request = Request.repositoryDeleteMirror(
            handle,
