public class File {
    internal let client: Client
    public let handle: FileHandle

    internal init(_ client: Client, _ handle: FileHandle) {
        self.client = client
        self.handle = handle
    }

    /// Closes the file.
    public func close() async throws {
        let request = Request.fileClose(
            handle,
        )
        let response = try await client.invoke(request)
        switch response {
        case .unit:
            return
        default:
            throw UnexpectedResponse()
        }
    }

    /// Flushes any pending writes to the file.
    public func flush() async throws {
        let request = Request.fileFlush(
            handle,
        )
        let response = try await client.invoke(request)
        switch response {
        case .unit:
            return
        default:
            throw UnexpectedResponse()
        }
    }

    /// Returns the length of the file in bytes
    public func getLength() async throws -> UInt64 {
        let request = Request.fileGetLength(
            handle,
        )
        let response = try await client.invoke(request)
        switch response {
        case .u64(let value): return value
        default:
            throw UnexpectedResponse()
        }
    }

    /// Returns the sync progress of this file, that is, the total byte size of all the blocks of
    /// this file that's already been downloaded.
    ///
    /// Note that Ouisync downloads the blocks in random order, so until the file's been completely
    /// downloaded, the already downloaded blocks are not guaranteed to continuous (there might be
    /// gaps).
    public func getProgress() async throws -> UInt64 {
        let request = Request.fileGetProgress(
            handle,
        )
        let response = try await client.invoke(request)
        switch response {
        case .u64(let value): return value
        default:
            throw UnexpectedResponse()
        }
    }

    /// Reads `size` bytes from the file starting at `offset` bytes from the beginning of the file.
    public func read(_ offset: UInt64, _ size: UInt64) async throws -> Data {
        let request = Request.fileRead(
            handle,
            offset,
            size,
        )
        let response = try await client.invoke(request)
        switch response {
        case .bytes(let value): return value
        default:
            throw UnexpectedResponse()
        }
    }

    /// Truncates the file to the given length.
    public func truncate(_ len: UInt64) async throws {
        let request = Request.fileTruncate(
            handle,
            len,
        )
        let response = try await client.invoke(request)
        switch response {
        case .unit:
            return
        default:
            throw UnexpectedResponse()
        }
    }

    /// Writes the data to the file at the given offset.
    public func write(_ offset: UInt64, _ data: Data) async throws {
        let request = Request.fileWrite(
            handle,
            offset,
            data,
        )
        let response = try await client.invoke(request)
        switch response {
        case .unit:
            return
        default:
            throw UnexpectedResponse()
        }
    }

    public static func == (lhs: File, rhs: File) -> Bool {
        return lhs.handle == rhs.handle
    }

    public var description: String { "\(type(of: self))(\(handle))" }
}

